def solve(nums, target):
    left, right = 0, len(nums) - 1
    while left < right:
        total = nums[left] + nums[right]
        if total == target:
            return left, right
        if total < target:
            left += 1
        else:
            right -= 1
    return -1, -1

# Additional checks for pitfalls
def check_no_solution(nums, target):
    # Check if no solution exists
    if len(nums) < 2:
        return True  # Not enough numbers to form a pair
    seen = set()
    for num in nums:
        if target - num in seen:
            return False
        seen.add(num)
    return True

# Updated solve function with no-solution check
def solve_with_checks(nums, target):
    if check_no_solution(nums, target):
        return -1, -1
    return solve(nums, target)
